import java.util.*;

public static long[][] solve(long[][] grid, long x, long y, long k) {
    int m = grid.length;
    int n = grid[0].length;

    // Create a copy of the grid to avoid modifying the original
    long[][] result = new long[m][n];
    for (int i = 0; i < m; i++) {
        System.arraycopy(grid[i], 0, result[i], 0, n);
    }

    // Perform vertical flip on the submatrix
    for (int i = 0; i < k / 2; i++) {
        // Swap the i-th row with the (k - 1 - i)-th row in the submatrix
        long[] row1 = result[x + i][y];
        long[] row2 = result[x + k - 1 - i][y];

        // Swap the rows
        for (int j = 0; j < n; j++) {
            long temp = row1[j];
            row1[j] = row2[j];
            row2[j] = temp;
        }
    }

    return result;
}
